import sys

def main():
    n = int(sys.stdin.readline())
    a = [0] * n
    b = [0] * n
    for i in range(n):
        a[i], b[i] = map(int, sys.stdin.readline().split())

    for i in range(n - 1):
        if a[i] < a[i + 1] and b[i] > b[i + 1]:
            print('unrated')
            return
    if a == b:
        print('maybe')
    else:
        print('rated')

if __name__ == '__main__':
    main()
